def is_spam_rule(email):
    # Example rule-based checks
    sender = email.get('sender')
    subject = email.get('subject','').lower()
    body = email.get('body','').lower()

    if sender == 'promotions@online.com':
        return True
    if 'tax review' in subject and sender.endswith('@online.com'):
        return True
    if 'deposit' in body:
        return True
    return False

# Usage: move emails for which is_spam_rule(email) is True to the spam folder
